'use strict';

const buttonActions = [];
/*
  Represents a button action.
  The handler is a no-args function that runs when the URI is navigated to from a button.
  Plugin actions live in their sandbox; their handler here just forwards an
  action-invoke message to the owning iframe (wired up in plugin-host.js).
*/
class Action {
  constructor(displayName, uri, handler) {
    this.displayName = displayName;
    this.uri = uri;
    this.handler = handler;
  }
  static get list() {
    return buttonActions;
  }
  static runURI(uri) {
    const action = buttonActions.find(action => action.uri === uri);
    if (action) action.handler();
  }
}

// Default action: open settings page
buttonActions.push(new Action('Open settings page', 'action://open-settings', () => location.href = '/settings.html'));

// Register a plugin-contributed action. Called by plugin-host when an iframe
// sends a register-action message. `uri` is the full action:// URI and `handler`
// forwards invocation back to the plugin's iframe.
function registerPluginAction(displayName, uri, handler) {
  // Avoid duplicates if the same action is registered on both global runs.
  if (buttonActions.some(action => action.uri === uri)) return;
  buttonActions.push(new Action(displayName, uri, handler));
}

export default Action;
export {registerPluginAction};
